/**
 * @brief Select the carousel orientation for this demo.
 *
 * Set to 0 for HORIZONTAL, 1 for VERTICAL.
 * All layout macros are derived automatically from this single switch.
 */
#define CARD_LIST_DEMO_ORIENTATION  0   /* 0 = HORIZONTAL, 1 = VERTICAL */

/* Screen dimensions */
#define SCREEN_W    480
#define SCREEN_H    480

/* Card dimensions (logical pixels) */
#define CARD_W      160
#define CARD_H      200

/* Number of data cards */
#define DEMO_CARD_COUNT   8

/* ---- Layout and behaviour derived from CARD_LIST_DEMO_ORIENTATION ---- */
#if CARD_LIST_DEMO_ORIENTATION == 0
/* Horizontal: list spans full screen width, centred vertically */
#  define DEMO_DIR      0
#  define DEMO_LIST_X   0
#  define DEMO_LIST_Y   ((SCREEN_H - CARD_H) / 2)
#  define DEMO_LIST_W   SCREEN_W
#  define DEMO_LIST_H   CARD_H
#  define DEMO_CARD_W   CARD_W
#  define DEMO_CARD_H   CARD_H
#  define DEMO_DCOUNT   5
#  define DEMO_LOOP     true
#  define DEMO_INWARD   true
#else
/* Vertical: list spans full screen height, centred horizontally */
#  define DEMO_DIR      1
#  define DEMO_LIST_X   ((SCREEN_W - CARD_W) / 2)
#  define DEMO_LIST_Y   0
#  define DEMO_LIST_W   CARD_W
#  define DEMO_LIST_H   SCREEN_H
#  define DEMO_CARD_W   CARD_H
#  define DEMO_CARD_H   CARD_W
#  define DEMO_DCOUNT   5
#  define DEMO_LOOP     true
#  define DEMO_INWARD   false
#endif

/* ---- Navigation button dimensions and positions --------------------------- */
#define BTN_W  70
#define BTN_H  40

#if CARD_LIST_DEMO_ORIENTATION == 0
/* Horizontal: buttons centred below the card list. */
#  define BTN_PREV_X  (SCREEN_W / 2 - BTN_W - 10)
#  define BTN_NEXT_X  (SCREEN_W / 2 + 10)
#  define BTN_Y       (DEMO_LIST_Y + DEMO_LIST_H + 40)
#else
/* Vertical: buttons to the left and right of the list column, vertically centred. */
#  define BTN_PREV_X  (DEMO_LIST_X - BTN_W - 30)
#  define BTN_NEXT_X  (DEMO_LIST_X + DEMO_LIST_W + 30)
#  define BTN_Y       (DEMO_LIST_Y + DEMO_LIST_H - BTN_H - 10)
#endif

