/*============================================================================*
 *                     Navigation buttons
 *============================================================================*/

static void on_btn_prev_click(void *obj, gui_event_t *e)
{
    (void)obj; (void)e;
    int count = (int)s_list->card_count;
    if (count == 0) { return; }
    int idx  = gui_card_list_get_current_index(s_list);
    int prev = s_list->loop ? (idx - 1 + count) % count
               : (idx - 1 >= 0 ? idx - 1 : 0);
    gui_card_list_scroll_to_card(s_list, prev);
}

static void on_btn_next_click(void *obj, gui_event_t *e)
{
    (void)obj; (void)e;
    int count = (int)s_list->card_count;
    if (count == 0) { return; }
    int idx  = gui_card_list_get_current_index(s_list);
    int next = s_list->loop ? (idx + 1) % count
               : (idx + 1 < count ? idx + 1 : count - 1);
    gui_card_list_scroll_to_card(s_list, next);
}

static void create_nav_buttons(gui_obj_t *root)
{
    gui_win_t *btn_prev = gui_win_create(root, "btn_prev",
                                         BTN_PREV_X, BTN_Y, BTN_W, BTN_H);
    gui_rect_create(btn_prev, "prev_bg", 0, 0, BTN_W, BTN_H, 8,
                    gui_rgba(0x55, 0x55, 0xAA, 0xCC));
    gui_win_click(btn_prev, on_btn_prev_click, NULL);

    gui_win_t *btn_next = gui_win_create(root, "btn_next",
                                         BTN_NEXT_X, BTN_Y, BTN_W, BTN_H);
    gui_rect_create(btn_next, "next_bg", 0, 0, BTN_W, BTN_H, 8,
                    gui_rgba(0x33, 0xAA, 0x77, 0xCC));
    gui_win_click(btn_next, on_btn_next_click, NULL);
}

/*============================================================================*
 *                     App initialisation
 *============================================================================*/

static int app_init(void)
{
    gui_obj_t *root = gui_obj_get_root();

    s_list = gui_card_list_create(root, "cards",
                                  DEMO_LIST_X, DEMO_LIST_Y,
                                  DEMO_LIST_W, DEMO_LIST_H,
                                  DEMO_CARD_W, DEMO_CARD_H,
                                  DEMO_DCOUNT,
                                  DEMO_DIR,
                                  card_design, NULL);
    gui_card_list_set_card_count(s_list, DEMO_CARD_COUNT);
    gui_card_list_enable_loop(s_list, DEMO_LOOP);
    gui_card_list_set_face_inward(s_list, DEMO_INWARD);

    create_nav_buttons(root);
    update_status();

    return 0;
}

GUI_INIT_APP_EXPORT(app_init);
